   1→//! Container management for sandboxed browser instances.
   2→//!
   3→//! Supports Docker, Podman, and Apple Container backends, auto-detecting the
   4→//! best available option (Apple Container on macOS → Podman → Docker).
   5→
   6→use std::{fmt::Display, process::Command};
   7→
   8→use {
   9→    crate::error::Error,
  10→    tracing::{debug, info, warn},
  11→};
  12→
  13→type Result<T> = std::result::Result<T, Error>;
  14→
  15→trait ContextExt<T> {
  16→    fn context(self, context: impl Into<String>) -> Result<T>;
  17→
  18→    fn with_context<C, F>(self, f: F) -> Result<T>
  19→    where
  20→        C: Into<String>,
  21→        F: FnOnce() -> C;
  22→}
  23→
  24→impl<T, E> ContextExt<T> for std::result::Result<T, E>
  25→where
  26→    E: Display,
  27→{
  28→    fn context(self, context: impl Into<String>) -> Result<T> {
  29→        let context = context.into();
  30→        self.map_err(|source| Error::LaunchFailed(format!("{context}: {source}")))
  31→    }
  32→
  33→    fn with_context<C, F>(self, f: F) -> Result<T>
  34→    where
  35→        C: Into<String>,
  36→        F: FnOnce() -> C,
  37→    {
  38→        let context = f().into();
  39→        self.map_err(|source| Error::LaunchFailed(format!("{context}: {source}")))
  40→    }
  41→}
  42→
  43→impl<T> ContextExt<T> for Option<T> {
  44→    fn context(self, context: impl Into<String>) -> Result<T> {
  45→        self.ok_or_else(|| Error::LaunchFailed(context.into()))
  46→    }
  47→
  48→    fn with_context<C, F>(self, f: F) -> Result<T>
  49→    where
  50→        C: Into<String>,
  51→        F: FnOnce() -> C,
  52→    {
  53→        self.ok_or_else(|| Error::LaunchFailed(f().into()))
  54→    }
  55→}
  56→
  57→fn browser_container_name_prefix(container_prefix: &str) -> String {
  58→    format!("{container_prefix}-")
  59→}
  60→
  61→fn new_browser_container_name(container_prefix: &str) -> String {
  62→    format!(
  63→        "{}{}",
  64→        browser_container_name_prefix(container_prefix),
  65→        uuid::Uuid::new_v4().as_simple()
  66→    )
  67→}
  68→
  69→/// Container backend type.
  70→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
  71→pub enum ContainerBackend {
  72→    Docker,
  73→    Podman,
  74→    #[cfg(target_os = "macos")]
  75→    AppleContainer,
  76→}
  77→
  78→impl ContainerBackend {
  79→    /// Get the CLI command name for this backend.
  80→    fn cli(&self) -> &'static str {
  81→        match self {
  82→            Self::Docker => "docker",
  83→            Self::Podman => "podman",
  84→            #[cfg(target_os = "macos")]
  85→            Self::AppleContainer => "container",
  86→        }
  87→    }
  88→
  89→    /// Check if this backend is available.
  90→    fn is_available(&self) -> bool {
  91→        is_cli_available(self.cli())
  92→    }
  93→}
  94→
  95→fn stop_container_by_id(backend: ContainerBackend, container_id: &str) {
  96→    let cli = backend.cli();
  97→    let result = Command::new(cli).args(["stop", container_id]).output();
  98→
  99→    match result {
 100→        Ok(output) if output.status.success() => {
 101→            debug!(container_id, backend = cli, "browser container stopped");
 102→        },
 103→        Ok(output) => {
 104→            let stderr = String::from_utf8_lossy(&output.stderr);
 105→            warn!(
 106→                container_id,
 107→                backend = cli,
 108→                error = %stderr.trim(),
 109→                "failed to stop browser container"
 110→            );
 111→        },
 112→        Err(e) => {
 113→            warn!(
 114→                container_id,
 115→                backend = cli,
 116→                error = %e,
 117→                "failed to run {} stop",
 118→                cli
 119→            );
 120→        },
 121→    }
 122→
 123→    // Apple Container requires explicit deletion after stop.
 124→    #[cfg(target_os = "macos")]
 125→    if backend == ContainerBackend::AppleContainer {
 126→        match Command::new("container")
 127→            .args(["rm", container_id])
 128→            .output()
 129→        {
 130→            Ok(output) if output.status.success() => {
 131→                debug!(container_id, "browser container removed");
 132→            },
 133→            Ok(output) => {
 134→                let stderr = String::from_utf8_lossy(&output.stderr);
 135→                warn!(
 136→                    container_id,
 137→                    error = %stderr.trim(),
 138→                    "failed to remove browser container"
 139→                );
 140→            },
 141→            Err(e) => {
 142→                warn!(container_id, error = %e, "failed to run container rm");
 143→            },
 144→        }
 145→    }
 146→}
 147→
 148→/// A running browser container instance.
 149→pub struct BrowserContainer {
 150→    /// Container ID or name.
 151→    container_id: String,
 152→    /// Host port mapped to the container's CDP port.
 153→    host_port: u16,
 154→    /// Hostname or IP used to connect to the container.
 155→    host: String,
 156→    /// The image used.
 157→    #[allow(dead_code)]
 158→    image: String,
 159→    /// The container backend being used.
 160→    backend: ContainerBackend,
 161→}
 162→
 163→impl BrowserContainer {
 164→    /// Start a new browser container using the auto-detected backend.
 165→    ///
 166→    /// Returns a container instance with the host port for CDP connections.
 167→    /// `container_host` is the hostname/IP used to reach the container (e.g.
 168→    /// `"127.0.0.1"` on the host, `"host.docker.internal"` from inside Docker).
 169→    /// When `profile_dir` is `Some`, the host directory is mounted into the
 170→    /// container so that browser profile data persists across sessions.
 171→    pub fn start(
 172→        image: &str,
 173→        container_prefix: &str,
 174→        viewport_width: u32,
 175→        viewport_height: u32,
 176→        low_memory_threshold_mb: u64,
 177→        session_timeout_ms: u64,
 178→        profile_dir: Option<&std::path::Path>,
 179→        container_host: &str,
 180→    ) -> Result<Self> {
 181→        let backend = detect_backend()?;
 182→        Self::start_with_backend(
 183→            backend,
 184→            image,
 185→            container_prefix,
 186→            viewport_width,
 187→            viewport_height,
 188→            low_memory_threshold_mb,
 189→            session_timeout_ms,
 190→            profile_dir,
 191→            container_host,
 192→        )
 193→    }
 194→
 195→    /// Start a new browser container with a specific backend.
 196→    pub fn start_with_backend(
 197→        backend: ContainerBackend,
 198→        image: &str,
 199→        container_prefix: &str,
 200→        viewport_width: u32,
 201→        viewport_height: u32,
 202→        low_memory_threshold_mb: u64,
 203→        session_timeout_ms: u64,
 204→        profile_dir: Option<&std::path::Path>,
 205→        container_host: &str,
 206→    ) -> Result<Self> {
 207→        use std::time::Instant;
 208→
 209→        if !backend.is_available() {
 210→            return Err(Error::LaunchFailed(format!(
 211→                "{} is not available. Please install it to use sandboxed browser.",
 212→                backend.cli()
 213→            )));
 214→        }
 215→
 216→        // Find an available port
 217→        let host_port = find_available_port()?;
 218→
 219→        info!(
 220→            image,
 221→            host_port,
 222→            backend = backend.cli(),
 223→            "starting browser container"
 224→        );
 225→
 226→        let t0 = Instant::now();
 227→        let container_id = match backend {
 228→            ContainerBackend::Docker | ContainerBackend::Podman => start_oci_container(
 229→                backend,
 230→                image,
 231→                container_prefix,
 232→                host_port,
 233→                viewport_width,
 234→                viewport_height,
 235→                low_memory_threshold_mb,
 236→                session_timeout_ms,
 237→                profile_dir,
 238→            )?,
 239→            #[cfg(target_os = "macos")]
 240→            ContainerBackend::AppleContainer => start_apple_container(
 241→                image,
 242→                container_prefix,
 243→                host_port,
 244→                viewport_width,
 245→                viewport_height,
 246→                low_memory_threshold_mb,
 247→                session_timeout_ms,
 248→                profile_dir,
 249→            )?,
 250→        };
 251→
 252→        info!(
 253→            container_id,
 254→            host_port,
 255→            backend = backend.cli(),
 256→            elapsed_ms = t0.elapsed().as_millis() as u64,
 257→            "browser container process started, waiting for Chrome readiness"
 258→        );
 259→
 260→        // Wait for the container to be ready
 261→        if let Err(error) = wait_for_ready(container_host, host_port) {
 262→            warn!(
 263→                container_id,
 264→                host_port,
 265→                backend = backend.cli(),
 266→                error = %error,
 267→                "browser container failed readiness check, cleaning up"
 268→            );
 269→            stop_container_by_id(backend, &container_id);
 270→            return Err(error);
 271→        }
 272→
 273→        info!(
 274→            container_id,
 275→            host_port,
 276→            backend = backend.cli(),
 277→            total_startup_ms = t0.elapsed().as_millis() as u64,
 278→            "browser container ready"
 279→        );
 280→
 281→        Ok(Self {
 282→            container_id,
 283→            host_port,
 284→            host: container_host.to_string(),
 285→            image: image.to_string(),
 286→            backend,
 287→        })
 288→    }
 289→
 290→    /// Get the WebSocket URL for CDP connection.
 291→    #[must_use]
 292→    pub fn websocket_url(&self) -> String {
 293→        // browserless/chrome provides a direct WebSocket endpoint
 294→        format!("ws://{}:{}", self.host, self.host_port)
 295→    }
 296→
 297→    /// Get the HTTP URL for health checks.
 298→    #[must_use]
 299→    pub fn http_url(&self) -> String {
 300→        format!("http://{}:{}", self.host, self.host_port)
 301→    }
 302→
 303→    /// Stop and remove the container.
 304→    pub fn stop(&self) {
 305→        info!(
 306→            container_id = %self.container_id,
 307→            backend = self.backend.cli(),
 308→            "stopping browser container"
 309→        );
 310→        stop_container_by_id(self.backend, &self.container_id);
 311→    }
 312→
 313→    /// Get the container ID.
 314→    #[must_use]
 315→    pub fn id(&self) -> &str {
 316→        &self.container_id
 317→    }
 318→
 319→    /// Get the backend being used.
 320→    #[must_use]
 321→    pub fn backend(&self) -> ContainerBackend {
 322→        self.backend
 323→    }
 324→}
 325→
 326→impl Drop for BrowserContainer {
 327→    fn drop(&mut self) {
 328→        self.stop();
 329→    }
 330→}
 331→
 332→/// Path inside the container where the browser profile is mounted.
 333→const CONTAINER_PROFILE_PATH: &str = "/data/browser-profile";
 334→
 335→/// Build the `DEFAULT_LAUNCH_ARGS` env-var value for containerised Chrome.
 336→///
 337→/// Always includes `--window-size`; appends low-memory flags when the host
 338→/// system RAM is below the given threshold. Adds `--user-data-dir` when a
 339→/// container-side profile path is provided.
 340→fn build_container_launch_args(
 341→    viewport_width: u32,
 342→    viewport_height: u32,
 343→    low_memory_threshold_mb: u64,
 344→    container_profile_dir: Option<&str>,
 345→    backend: ContainerBackend,
 346→) -> String {
 347→    use crate::pool::low_memory_chrome_args;
 348→
 349→    let mut args = vec![format!("--window-size={viewport_width},{viewport_height}")];
 350→
 351→    if let Some(profile_dir) = container_profile_dir {
 352→        args.push(format!("--user-data-dir={profile_dir}"));
 353→    }
 354→
 355→    // Apple Container VMs may not provide /dev/shm reliably; tell Chrome to
 356→    // write shared-memory segments to /tmp instead.
 357→    #[cfg(target_os = "macos")]
 358→    if backend == ContainerBackend::AppleContainer {
 359→        args.push("--disable-dev-shm-usage".to_string());
 360→    }
 361→    #[cfg(not(target_os = "macos"))]
 362→    let _ = backend;
 363→
 364→    if low_memory_threshold_mb > 0 {
 365→        let mut sys = sysinfo::System::new();
 366→        sys.refresh_memory();
 367→        let total_mb = sys.total_memory() / (1024 * 1024);
 368→        for flag in low_memory_chrome_args(total_mb, low_memory_threshold_mb) {
 369→            args.push((*flag).to_string());
 370→        }
 371→    }
 372→
 373→    let joined = args
 374→        .iter()
 375→        .map(|a| format!("\"{a}\""))
 376→        .collect::<Vec<_>>()
 377→        .join(",");
 378→    format!("DEFAULT_LAUNCH_ARGS=[{joined}]")
 379→}
 380→
 381→/// Compute the browserless container `TIMEOUT` (in ms) from pool lifecycle settings.
 382→///
 383→/// The result is `max(idle_timeout_secs, max_instance_lifetime_secs)` converted
 384→/// to milliseconds, then floored against `navigation_timeout_ms` so that a single
 385→/// long navigation cannot exceed the container's own timeout. The final value is
 386→/// capped at `max_instance_lifetime_secs * 1000` to prevent disagree­ment with the
 387→/// Moltis-side hard TTL when `navigation_timeout_ms` is very large.
 388→pub(crate) fn browserless_session_timeout_ms(
 389→    idle_timeout_secs: u64,
 390→    navigation_timeout_ms: u64,
 391→    max_instance_lifetime_secs: u64,
 392→) -> u64 {
 393→    let ceiling_ms = max_instance_lifetime_secs.saturating_mul(1000);
 394→    idle_timeout_secs
 395→        .max(max_instance_lifetime_secs)
 396→        .saturating_mul(1000)
 397→        .max(navigation_timeout_ms)
 398→        .min(ceiling_ms)
 399→}
 400→
 401→fn browserless_container_env(session_timeout_ms: u64) -> Vec<String> {
 402→    vec![
 403→        format!("TIMEOUT={session_timeout_ms}"),
 404→        "MAX_CONCURRENT_SESSIONS=1".to_string(),
 405→        "PREBOOT_CHROME=true".to_string(),
 406→    ]
 407→}
 408→
 409→/// Start a Docker container for the browser.
 410→fn start_oci_container(
 411→    backend: ContainerBackend,
 412→    image: &str,
 413→    container_prefix: &str,
 414→    host_port: u16,
 415→    viewport_width: u32,
 416→    viewport_height: u32,
 417→    low_memory_threshold_mb: u64,
 418→    session_timeout_ms: u64,
 419→    profile_dir: Option<&std::path::Path>,
 420→) -> Result<String> {
 421→    let cli = backend.cli();
 422→    let container_name = new_browser_container_name(container_prefix);
 423→
 424→    let container_profile_dir = profile_dir.map(|_| CONTAINER_PROFILE_PATH);
 425→    let launch_args = build_container_launch_args(
 426→        viewport_width,
 427→        viewport_height,
 428→        low_memory_threshold_mb,
 429→        container_profile_dir,
 430→        backend,
 431→    );
 432→    let browserless_env = browserless_container_env(session_timeout_ms);
 433→
 434→    let mut run_args = vec![
 435→        "run".to_string(),
 436→        "-d".to_string(),
 437→        "--rm".to_string(),
 438→        "--name".to_string(),
 439→        container_name.clone(),
 440→        "-p".to_string(),
 441→        format!("{}:3000", host_port),
 442→        "-e".to_string(),
 443→        launch_args,
 444→        "--shm-size=2gb".to_string(),
 445→    ];
 446→
 447→    for env in browserless_env {
 448→        run_args.push("-e".to_string());
 449→        run_args.push(env);
 450→    }
 451→
 452→    // Mount the profile directory if persistence is enabled
 453→    if let Some(host_path) = profile_dir {
 454→        run_args.push("-v".to_string());
 455→        run_args.push(format!(
 456→            "{}:{}:rw",
 457→            host_path.display(),
 458→            CONTAINER_PROFILE_PATH
 459→        ));
 460→    }
 461→
 462→    run_args.push(image.to_string());
 463→
 464→    let output = Command::new(cli)
 465→        .args(&run_args)
 466→        .output()
 467→        .with_context(|| format!("failed to run {cli} command"))?;
 468→
 469→    if !output.status.success() {
 470→        let stderr = String::from_utf8_lossy(&output.stderr);
 471→        return Err(Error::LaunchFailed(format!(
 472→            "failed to start {cli} container: {}",
 473→            stderr.trim()
 474→        )));
 475→    }
 476→
 477→    if container_name.is_empty() {
 478→        return Err(Error::LaunchFailed(format!(
 479→            "{cli} container name is empty"
 480→        )));
 481→    }
 482→
 483→    Ok(container_name)
 484→}
