 486→/// Start an Apple Container for the browser.
 487→#[cfg(target_os = "macos")]
 488→fn start_apple_container(
 489→    image: &str,
 490→    container_prefix: &str,
 491→    host_port: u16,
 492→    viewport_width: u32,
 493→    viewport_height: u32,
 494→    low_memory_threshold_mb: u64,
 495→    session_timeout_ms: u64,
 496→    profile_dir: Option<&std::path::Path>,
 497→) -> Result<String> {
 498→    let container_name = new_browser_container_name(container_prefix);
 499→
 500→    let container_profile_dir = profile_dir.map(|_| CONTAINER_PROFILE_PATH);
 501→    let launch_args = build_container_launch_args(
 502→        viewport_width,
 503→        viewport_height,
 504→        low_memory_threshold_mb,
 505→        container_profile_dir,
 506→        ContainerBackend::AppleContainer,
 507→    );
 508→    let browserless_env = browserless_container_env(session_timeout_ms);
 509→
 510→    let mut container_args = vec![
 511→        "run".to_string(),
 512→        "-d".to_string(),
 513→        "--name".to_string(),
 514→        container_name.clone(),
 515→        "-p".to_string(),
 516→        format!("{}:3000", host_port),
 517→        "-e".to_string(),
 518→        launch_args,
 519→        // Chrome requires shared memory for rendering; Docker uses --shm-size=2gb,
 520→        // Apple Container doesn't support --shm-size so mount tmpfs at /dev/shm.
 521→        "--tmpfs".to_string(),
 522→        "/dev/shm".to_string(),
 523→    ];
 524→
 525→    for env in browserless_env {
 526→        container_args.push("-e".to_string());
 527→        container_args.push(env);
 528→    }
 529→
 530→    // Mount the profile directory if persistence is enabled
 531→    if let Some(host_path) = profile_dir {
 532→        container_args.push("-v".to_string());
 533→        container_args.push(format!(
 534→            "{}:{}",
 535→            host_path.display(),
 536→            CONTAINER_PROFILE_PATH
 537→        ));
 538→    }
 539→
 540→    container_args.push(image.to_string());
 541→
 542→    let output = Command::new("container")
 543→        .args(&container_args)
 544→        .output()
 545→        .context("failed to run container command")?;
 546→
 547→    if !output.status.success() {
 548→        let stderr = String::from_utf8_lossy(&output.stderr);
 549→        return Err(Error::LaunchFailed(format!(
 550→            "failed to start apple container: {}",
 551→            stderr.trim()
 552→        )));
 553→    }
 554→
 555→    Ok(container_name)
 556→}
 557→
 558→/// Detect the best available container backend.
 559→///
 560→/// Prefers Apple Container on macOS when available and functional (VM-isolated),
 561→/// then Podman (daemonless), then Docker.
 562→pub fn detect_backend() -> Result<ContainerBackend> {
 563→    #[cfg(target_os = "macos")]
 564→    {
 565→        if is_apple_container_functional() {
 566→            info!("browser sandbox backend: apple-container (VM-isolated)");
 567→            return Ok(ContainerBackend::AppleContainer);
 568→        }
 569→    }
 570→
 571→    if ContainerBackend::Podman.is_available() {
 572→        info!("browser sandbox backend: podman (daemonless)");
 573→        return Ok(ContainerBackend::Podman);
 574→    }
 575→
 576→    if is_docker_available() {
 577→        info!("browser sandbox backend: docker");
 578→        return Ok(ContainerBackend::Docker);
 579→    }
 580→
 581→    Err(Error::LaunchFailed(
 582→        "No container runtime available. Please install Docker or Podman to use sandboxed browser mode."
 583→            .to_string(),
 584→    ))
 585→}
 586→
 587→/// Check if Apple Container is actually functional (has required plugins).
 588→#[cfg(target_os = "macos")]
 589→fn is_apple_container_functional() -> bool {
 590→    if !is_cli_available("container") {
 591→        return false;
 592→    }
 593→    Command::new("container")
 594→        .args(["image", "pull", "--help"])
 595→        .stdout(std::process::Stdio::null())
 596→        .stderr(std::process::Stdio::null())
 597→        .status()
 598→        .is_ok_and(|s| s.success())
 599→}
 600→
 601→/// Check if a CLI tool is available.
 602→fn is_cli_available(name: &str) -> bool {
 603→    Command::new(name)
 604→        .arg("--version")
 605→        .stdout(std::process::Stdio::null())
 606→        .stderr(std::process::Stdio::null())
 607→        .status()
 608→        .is_ok_and(|s| s.success())
 609→}
 610→
 611→/// Find an available TCP port.
 612→fn find_available_port() -> Result<u16> {
 613→    let listener =
 614→        std::net::TcpListener::bind("127.0.0.1:0").context("failed to bind to ephemeral port")?;
 615→
 616→    let port = listener
 617→        .local_addr()
 618→        .context("failed to get local address")?
 619→        .port();
 620→
 621→    drop(listener);
 622→    Ok(port)
 623→}
 624→
 625→/// Wait for the container to be ready by probing the Chrome DevTools endpoint.
 626→///
 627→/// TCP connectivity alone isn't sufficient - Chrome inside the container may accept
 628→/// connections before it's ready to handle WebSocket requests. We probe `/json/version`
 629→/// which browserless exposes when Chrome is truly ready.
 630→fn wait_for_ready(host: &str, port: u16) -> Result<()> {
 631→    use std::time::{Duration, Instant};
 632→
 633→    let url = format!("http://{}:{}/json/version", host, port);
 634→    let timeout = Duration::from_secs(60);
 635→    let start = Instant::now();
 636→    let mut attempts: u32 = 0;
 637→
 638→    info!(
 639→        url,
 640→        timeout_secs = 60,
 641→        "waiting for browser container Chrome readiness"
 642→    );
 643→
 644→    loop {
 645→        let elapsed = start.elapsed();
 646→        if elapsed > timeout {
 647→            warn!(
 648→                attempts,
 649→                elapsed_ms = elapsed.as_millis() as u64,
 650→                "browser container failed to become ready within {}s",
 651→                timeout.as_secs()
 652→            );
 653→            return Err(Error::LaunchFailed(format!(
 654→                "browser container failed to become ready within {}s ({} probe attempts)",
 655→                timeout.as_secs(),
 656→                attempts
 657→            )));
 658→        }
 659→
 660→        attempts += 1;
 661→
 662→        // Try HTTP GET /json/version - this endpoint returns 200 when Chrome is ready
 663→        match probe_http_endpoint(host, port) {
 664→            Ok(true) => {
 665→                info!(
 666→                    attempts,
 667→                    elapsed_ms = elapsed.as_millis() as u64,
 668→                    "browser container Chrome endpoint is ready"
 669→                );
 670→                return Ok(());
 671→            },
 672→            Ok(false) => {
 673→                // Log progress every 10 attempts (~5 seconds)
 674→                if attempts.is_multiple_of(10) {
 675→                    info!(
 676→                        attempts,
 677→                        elapsed_ms = elapsed.as_millis() as u64,
 678→                        "Chrome endpoint not ready yet, still probing"
 679→                    );
 680→                } else {
 681→                    debug!(attempts, "Chrome endpoint not ready yet, retrying");
 682→                }
 683→            },
 684→            Err(e) => {
 685→                // Log progress every 10 attempts (~5 seconds)
 686→                if attempts.is_multiple_of(10) {
 687→                    info!(
 688→                        attempts,
 689→                        elapsed_ms = elapsed.as_millis() as u64,
 690→                        error = %e,
 691→                        "probe failed, still retrying"
 692→                    );
 693→                } else {
 694→                    debug!(attempts, error = %e, "probe failed, retrying");
 695→                }
 696→            },
 697→        }
 698→
 699→        std::thread::sleep(Duration::from_millis(500));
 700→    }
 701→}
