 703→/// Probe the Chrome /json/version endpoint to check if it's ready.
 704→fn probe_http_endpoint(host: &str, port: u16) -> Result<bool> {
 705→    use std::{
 706→        io::{BufRead, BufReader, Write},
 707→        net::{TcpStream, ToSocketAddrs},
 708→        time::Duration,
 709→    };
 710→
 711→    let addr = format!("{}:{}", host, port);
 712→    let socket_addr = addr
 713→        .to_socket_addrs()
 714→        .map_err(|e| Error::LaunchFailed(format!("failed to resolve {addr}: {e}")))?
 715→        .next()
 716→        .ok_or_else(|| Error::LaunchFailed(format!("no addresses resolved for {addr}")))?;
 717→    let mut stream = TcpStream::connect_timeout(&socket_addr, Duration::from_secs(2))?;
 718→    stream.set_read_timeout(Some(Duration::from_secs(2)))?;
 719→    stream.set_write_timeout(Some(Duration::from_secs(2)))?;
 720→
 721→    // Send minimal HTTP request
 722→    let request =
 723→        format!("GET /json/version HTTP/1.1\r\nHost: {host}\r\nConnection: close\r\n\r\n");
 724→    stream.write_all(request.as_bytes())?;
 725→
 726→    // Read response status line
 727→    let mut reader = BufReader::new(stream);
 728→    let mut status_line = String::new();
 729→    reader.read_line(&mut status_line)?;
 730→
 731→    let ready = status_line.contains("200");
 732→    debug!(
 733→        port,
 734→        status_line = status_line.trim(),
 735→        ready,
 736→        "probe response"
 737→    );
 738→
 739→    Ok(ready)
 740→}
