 809→fn cleanup_stale_docker_browser_containers(container_prefix: &str) -> Result<usize> {
 810→    if !is_docker_available() {
 811→        return Ok(0);
 812→    }
 813→
 814→    let output = Command::new("docker")
 815→        .args(["ps", "-a", "--format", "{{.Names}}"])
 816→        .output()
 817→        .context("failed to list docker containers")?;
 818→    if !output.status.success() {
 819→        let stderr = String::from_utf8_lossy(&output.stderr);
 820→        return Err(Error::LaunchFailed(format!(
 821→            "docker ps failed while cleaning stale browser containers: {}",
 822→            stderr.trim()
 823→        )));
 824→    }
 825→
 826→    let names = parse_docker_container_names(&output.stdout, container_prefix);
 827→    let mut removed = 0usize;
 828→    for name in names {
 829→        let rm = Command::new("docker")
 830→            .args(["rm", "-f", &name])
 831→            .output()
 832→            .with_context(|| format!("failed to remove stale docker browser container {name}"))?;
 833→        if rm.status.success() {
 834→            removed += 1;
 835→        } else {
 836→            let stderr = String::from_utf8_lossy(&rm.stderr);
 837→            warn!(
 838→                container_name = %name,
 839→                error = %stderr.trim(),
 840→                "failed to remove stale docker browser container"
 841→            );
 842→        }
 843→    }
 844→
 845→    Ok(removed)
 846→}
