 848→#[cfg(target_os = "macos")]
 849→fn cleanup_stale_apple_browser_containers(container_prefix: &str) -> Result<usize> {
 850→    if !is_cli_available("container") {
 851→        return Ok(0);
 852→    }
 853→
 854→    let output = Command::new("container")
 855→        .args(["list", "--all", "--format", "json"])
 856→        .output()
 857→        .context("failed to list apple containers")?;
 858→    if !output.status.success() {
