 860→        return Err(Error::LaunchFailed(format!(
 861→            "container list failed while cleaning stale browser containers: {}",
 862→            stderr.trim()
 863→        )));
 864→    }
 865→
 866→    let names = parse_apple_container_names_for_prefix(&output.stdout, container_prefix)?;
 867→    let mut removed = 0usize;
 868→    for name in names {
 869→        let rm = Command::new("container")
 870→            .args(["delete", "--force", &name])
 871→            .output()
 872→            .with_context(|| format!("failed to remove stale apple browser container {name}"))?;
 873→        if rm.status.success() {
 874→            removed += 1;
 875→        } else {
 876→            let stderr = String::from_utf8_lossy(&rm.stderr);
 877→            warn!(
 878→                container_name = %name,
 879→                error = %stderr.trim(),
 880→                "failed to remove stale apple browser container"
 881→            );
 882→        }
 883→    }
 884→
 885→    Ok(removed)
 886→}
