 911→/// Pull the browser container image if not present.
 912→/// Falls back to Docker if the primary backend fails.
 913→pub fn ensure_image(image: &str) -> Result<()> {
 914→    let backend = detect_backend()?;
 915→
 916→    // Try primary backend first
 917→    let result = ensure_image_with_backend(backend, image);
 918→
 919→    // On macOS, if Apple Container fails, try Docker as fallback
 920→    #[cfg(target_os = "macos")]
 921→    if result.is_err() && backend == ContainerBackend::AppleContainer && is_docker_available() {
 922→        if let Err(ref e) = result {
 923→            warn!(
 924→                error = %e,
 925→                "Apple Container image pull failed, falling back to Docker"
 926→            );
 927→        }
 928→        return ensure_image_with_backend(ContainerBackend::Docker, image);
 929→    }
 930→
 931→    result
 932→}
