 934→/// Pull the browser container image using a specific backend.
 935→pub fn ensure_image_with_backend(backend: ContainerBackend, image: &str) -> Result<()> {
 936→    let cli = backend.cli();
 937→
 938→    // Check if image exists locally
 939→    let output = Command::new(cli)
 940→        .args(["image", "inspect", image])
 941→        .stdout(std::process::Stdio::null())
 942→        .stderr(std::process::Stdio::null())
 943→        .status()
 944→        .context("failed to check for image")?;
 945→
 946→    if output.success() {
 947→        info!(
 948→            image,
 949→            backend = cli,
 950→            "browser container image already present"
 951→        );
 952→        return Ok(());
 953→    }
 954→
 955→    info!(image, backend = cli, "pulling browser container image");
 956→
 957→    let output = match backend {
 958→        ContainerBackend::Docker | ContainerBackend::Podman => {
 959→            Command::new(cli).args(["pull", image]).output()
 960→        },
 961→        #[cfg(target_os = "macos")]
 962→        ContainerBackend::AppleContainer => {
 963→            Command::new(cli).args(["image", "pull", image]).output()
 964→        },
 965→    }
 966→    .context("failed to pull image")?;
 967→
 968→    if !output.status.success() {
 969→        let stderr = String::from_utf8_lossy(&output.stderr);
 970→        return Err(Error::LaunchFailed(format!(
 971→            "failed to pull browser image: {}",
 972→            stderr.trim()
 973→        )));
 974→    }
 975→
 976→    info!(
 977→        image,
 978→        backend = cli,
 979→        "browser container image pulled successfully"
 980→    );
 981→    Ok(())
 982→}
