  1→//! Browser manager providing high-level browser automation actions.
  2→
  3→use std::{sync::Arc, time::Instant};
  4→
  5→use {
  6→    base64::{Engine, engine::general_purpose::STANDARD as BASE64},
  7→    chromiumoxide::{
  8→        Page,
  9→        cdp::browser_protocol::{
 10→            input::{
 11→                DispatchKeyEventParams, DispatchKeyEventType, DispatchMouseEventParams,
 12→                DispatchMouseEventType, MouseButton,
 13→            },
 14→            page::CaptureScreenshotFormat,
 15→        },
 16→    },
 17→    tokio::time::{Duration, timeout},
 18→    tracing::{debug, info, warn},
 19→};
 20→
 21→use crate::{
 22→    error::Error,
 23→    pool::BrowserPool,
 24→    snapshot::{
 25→        extract_snapshot, find_element_by_ref, focus_element_by_ref, scroll_element_into_view,
 26→    },
 27→    types::{BrowserAction, BrowserConfig, BrowserPreference, BrowserRequest, BrowserResponse},
 28→};
 29→
 30→/// Extract session_id or return an error for actions that require an existing session.
 31→fn require_session(session_id: Option<&str>, action: &str) -> Result<String, Error> {
 32→    session_id
 33→        .map(String::from)
 34→        .ok_or_else(|| Error::InvalidAction(format!("{action} requires a session_id")))
 35→}
 36→
 37→/// Manage Chrome/Chromium instances with CDP.
 38→pub struct BrowserManager {
 39→    pool: Arc<BrowserPool>,
 40→    config: BrowserConfig,
 41→}
 42→
 43→impl Default for BrowserManager {
 44→    fn default() -> Self {
 45→        Self::new(BrowserConfig::default())
 46→    }
 47→}
 48→
 49→impl BrowserManager {
 50→    /// Create a new browser manager with the given configuration.
 51→    pub fn new(config: BrowserConfig) -> Self {
 52→        match crate::container::cleanup_stale_browser_containers(&config.container_prefix) {
 53→            Ok(removed) if removed > 0 => {
 54→                info!(
 55→                    removed,
 56→                    "removed stale browser containers from previous runs"
 57→                );
 58→            },
 59→            Ok(_) => {},
 60→            Err(e) => {
 61→                warn!(error = %e, "failed to clean stale browser containers at startup");
 62→            },
 63→        }
 64→
 65→        info!(
 66→            sandbox_image = %config.sandbox_image,
 67→            "browser manager initialized (sandbox mode controlled per-session)"
 68→        );
 69→
 70→        Self {
 71→            pool: Arc::new(BrowserPool::new(config.clone())),
 72→            config,
 73→        }
 74→    }
 75→
 76→    /// Check if browser support is enabled.
 77→    pub fn is_enabled(&self) -> bool {
 78→        self.config.enabled
 79→    }
 80→
 81→    /// Handle a browser request.
 82→    pub async fn handle_request(&self, request: BrowserRequest) -> BrowserResponse {
 83→        if !self.config.enabled {
 84→            return BrowserResponse::error(
 85→                request.session_id.unwrap_or_default(),
 86→                "browser support is disabled",
 87→                0,
 88→            );
 89→        }
 90→
 91→        // Determine sandbox mode from request (defaults to false/host)
 92→        let sandbox = request.sandbox.unwrap_or(false);
 93→
 94→        // Log the action with execution mode for visibility
 95→        let mode = if sandbox {
 96→            "sandbox"
 97→        } else {
 98→            "host"
 99→        };
100→        info!(
101→            action = %request.action,
102→            session_id = request.session_id.as_deref().unwrap_or("(new)"),
103→            browser = ?request.browser,
104→            execution_mode = mode,
105→            sandbox_image = %self.config.sandbox_image,
106→            "executing browser action"
107→        );
108→
109→        let start = Instant::now();
110→        let timeout_duration = Duration::from_millis(request.timeout_ms);
111→
112→        match timeout(
113→            timeout_duration,
114→            self.execute_action(
115→                request.session_id.as_deref(),
116→                request.action,
117→                sandbox,
118→                request.browser,
119→            ),
120→        )
121→        .await
122→        {
123→            Ok(result) => {
124→                let duration_ms = start.elapsed().as_millis() as u64;
125→                match result {
126→                    Ok((session_id, response)) => {
127→                        let mut resp = response;
128→                        resp.duration_ms = duration_ms;
129→                        resp.session_id = session_id;
130→                        resp
131→                    },
132→                    Err(e) => {
133→                        #[cfg(feature = "metrics")]
134→                        moltis_metrics::counter!(
135→                            moltis_metrics::browser::ERRORS_TOTAL,
136→                            "type" => e.to_string()
137→                        )
138→                        .increment(1);
139→
140→                        BrowserResponse::error(
141→                            request.session_id.unwrap_or_default(),
142→                            e.to_string(),
143→                            duration_ms,
144→                        )
145→                    },
146→                }
147→            },
148→            Err(_) => {
149→                #[cfg(feature = "metrics")]
150→                moltis_metrics::counter!(
151→                    moltis_metrics::browser::ERRORS_TOTAL,
152→                    "type" => "timeout"
153→                )
154→                .increment(1);
155→
156→                BrowserResponse::error(
157→                    request.session_id.unwrap_or_default(),
158→                    format!("operation timed out after {}ms", request.timeout_ms),
159→                    request.timeout_ms,
160→                )
161→            },
162→        }
163→    }
164→
165→    /// Clean up a session whose CDP connection has died and return an
166→    /// actionable error the agent can act on.
167→    async fn cleanup_stale_session(&self, session_id: &str, action: &str) -> Error {
168→        warn!(
169→            session_id,
170→            action, "browser connection dead, closing stale session"
171→        );
172→        let _ = self.pool.close_session(session_id).await;
173→        Error::ConnectionClosed(format!(
174→            "Browser session {session_id} lost its connection during {action}. \
175→             Please navigate to the page again to get a fresh session."
176→        ))
177→    }
178→
179→    /// Execute a browser action.
180→    async fn execute_action(
181→        &self,
182→        session_id: Option<&str>,
183→        action: BrowserAction,
184→        sandbox: bool,
185→        browser: Option<BrowserPreference>,
186→    ) -> Result<(String, BrowserResponse), Error> {
187→        // Navigate has its own retry-with-fresh-session logic, so handle it
188→        // separately to avoid double-cleanup.
189→        if let BrowserAction::Navigate { ref url } = action {
190→            return self.navigate(session_id, url, sandbox, browser).await;
191→        }
192→
193→        let action_name = action.to_string();
194→
195→        let result = match action {
196→            BrowserAction::Navigate { .. } => unreachable!(),
197→            BrowserAction::Screenshot {
198→                full_page,
199→                highlight_ref,
200→            } => {
201→                self.screenshot(session_id, full_page, highlight_ref, sandbox, browser)
202→                    .await
203→            },
204→            BrowserAction::Snapshot => self.snapshot(session_id, sandbox, browser).await,
205→            BrowserAction::Click { ref_ } => self.click(session_id, ref_, sandbox).await,
206→            BrowserAction::Type { ref_, text } => {
207→                self.type_text(session_id, ref_, &text, sandbox).await
208→            },
209→            BrowserAction::Scroll { ref_, x, y } => {
210→                self.scroll(session_id, ref_, x, y, sandbox).await
211→            },
212→            BrowserAction::Evaluate { code } => self.evaluate(session_id, &code, sandbox).await,
213→            BrowserAction::Wait {
214→                selector,
215→                ref_,
216→                timeout_ms,
217→            } => {
218→                self.wait(session_id, selector, ref_, timeout_ms, sandbox)
219→                    .await
220→            },
221→            BrowserAction::GetUrl => self.get_url(session_id, sandbox).await,
222→            BrowserAction::GetTitle => self.get_title(session_id, sandbox).await,
223→            BrowserAction::Back => self.go_back(session_id, sandbox).await,
224→            BrowserAction::Forward => self.go_forward(session_id, sandbox).await,
225→            BrowserAction::Refresh => self.refresh(session_id, sandbox).await,
226→            BrowserAction::Close => self.close(session_id, sandbox).await,
227→        };
228→
229→        // Detect stale connections for all non-Navigate actions
230→        match result {
231→            Err(ref e) if e.is_connection_error() => {
232→                let sid = session_id.unwrap_or("unknown");
233→                Err(self.cleanup_stale_session(sid, &action_name).await)
234→            },
235→            other => other,
236→        }
237→    }
238→
239→    /// Navigate to a URL.
240→    async fn navigate(
241→        &self,
242→        session_id: Option<&str>,
243→        url: &str,
244→        sandbox: bool,
245→        browser: Option<BrowserPreference>,
246→    ) -> Result<(String, BrowserResponse), Error> {
247→        // Validate URL before navigation
248→        validate_url(url)?;
249→
250→        // Check if the domain is allowed
251→        if !crate::types::is_domain_allowed(url, &self.config.allowed_domains) {
252→            return Err(Error::NavigationFailed(format!(
253→                "domain not in allowed list. Allowed domains: {:?}",
254→                self.config.allowed_domains
255→            )));
256→        }
257→
258→        let sid = self
259→            .pool
260→            .get_or_create(session_id, sandbox, browser)
261→            .await?;
262→        let page = self.pool.get_page(&sid).await?;
263→
264→        #[cfg(feature = "metrics")]
265→        let nav_start = Instant::now();
266→
267→        // Try navigation, retry with fresh session if connection is dead
268→        if let Err(e) = page.goto(url).await {
269→            let nav_err = Error::NavigationFailed(e.to_string());
270→            if nav_err.is_connection_error() {
271→                warn!(
272→                    session_id = sid,
273→                    "browser connection dead, closing session and retrying"
274→                );
275→                let _ = self.pool.close_session(&sid).await;
276→                // Retry with a fresh session (use same sandbox mode)
277→                let new_sid = self.pool.get_or_create(None, sandbox, browser).await?;
278→                let new_page = self.pool.get_page(&new_sid).await?;
279→                new_page
280→                    .goto(url)
281→                    .await
282→                    .map_err(|e| Error::NavigationFailed(e.to_string()))?;
283→                // Continue with the new session
284→                let _ = new_page.wait_for_navigation().await;
285→                let current_url = new_page.url().await.ok().flatten().unwrap_or_default();
286→                info!(
287→                    session_id = new_sid,
288→                    url = current_url,
289→                    "navigated to URL (after retry)"
290→                );
291→                return Ok((
292→                    new_sid.clone(),
293→                    BrowserResponse::success(new_sid, 0, sandbox).with_url(current_url),
294→                ));
295→            }
296→            return Err(nav_err);
297→        }
298→
299→        // Wait for network idle
300→        let _ = page.wait_for_navigation().await;
301→
302→        #[cfg(feature = "metrics")]
303→        {
304→            moltis_metrics::histogram!(moltis_metrics::browser::NAVIGATION_DURATION_SECONDS)
305→                .record(nav_start.elapsed().as_secs_f64());
306→        }
307→
308→        let current_url = page.url().await.ok().flatten().unwrap_or_default();
309→
310→        info!(session_id = sid, url = current_url, "navigated to URL");
311→
312→        Ok((
313→            sid.clone(),
314→            BrowserResponse::success(sid, 0, sandbox).with_url(current_url),
315→        ))
316→    }
317→
318→    /// Take a screenshot of the page.
319→    async fn screenshot(
320→        &self,
321→        session_id: Option<&str>,
322→        full_page: bool,
323→        highlight_ref: Option<u32>,
324→        sandbox: bool,
325→        browser: Option<BrowserPreference>,
326→    ) -> Result<(String, BrowserResponse), Error> {
327→        let sid = self
328→            .pool
329→            .get_or_create(session_id, sandbox, browser)
330→            .await?;
331→        let page = self.pool.get_page(&sid).await?;
332→
333→        // Optionally highlight an element before screenshot
334→        if let Some(ref_) = highlight_ref {
335→            let _ = self.highlight_element(&page, ref_).await;
336→        }
337→
338→        let screenshot = page
339→            .screenshot(
340→                chromiumoxide::page::ScreenshotParams::builder()
341→                    .format(CaptureScreenshotFormat::Png)
342→                    .full_page(full_page)
343→                    .build(),
344→            )
345→            .await
346→            .map_err(|e| Error::ScreenshotFailed(e.to_string()))?;
347→
348→        // Remove highlight after screenshot
349→        if highlight_ref.is_some() {
350→            let _ = self.remove_highlights(&page).await;
351→        }
352→
353→        // Use data URI format so the sanitizer can strip it for LLM context
354→        // while the UI can still display it as an image
355→        let data_uri = format!("data:image/png;base64,{}", BASE64.encode(&screenshot));
356→
357→        #[cfg(feature = "metrics")]
358→        moltis_metrics::counter!(moltis_metrics::browser::SCREENSHOTS_TOTAL).increment(1);
359→
360→        // Calculate approximate dimensions from PNG data (width/height are in bytes 16-23)
361→        let (width, height) = if screenshot.len() > 24 {
362→            let w = u32::from_be_bytes([
363→                screenshot[16],
364→                screenshot[17],
365→                screenshot[18],
366→                screenshot[19],
367→            ]);
368→            let h = u32::from_be_bytes([
369→                screenshot[20],
370→                screenshot[21],
371→                screenshot[22],
372→                screenshot[23],
373→            ]);
374→            (w, h)
375→        } else {
376→            (0, 0)
377→        };
378→
379→        info!(
380→            session_id = sid,
381→            bytes = screenshot.len(),
382→            width,
383→            height,
384→            full_page,
385→            "took screenshot"
386→        );
387→
388→        Ok((
389→            sid.clone(),
390→            BrowserResponse::success(sid, 0, sandbox)
391→                .with_screenshot(data_uri, self.config.device_scale_factor),
392→        ))
393→    }
394→
395→    /// Get a DOM snapshot with element references.
396→    ///
397→    /// Stale-connection errors are detected centrally in `execute_action()`.
398→    async fn snapshot(
399→        &self,
400→        session_id: Option<&str>,
401→        sandbox: bool,
402→        browser: Option<BrowserPreference>,
403→    ) -> Result<(String, BrowserResponse), Error> {
404→        let sid = self
405→            .pool
406→            .get_or_create(session_id, sandbox, browser)
407→            .await?;
408→        let page = self.pool.get_page(&sid).await?;
409→
410→        let snapshot = extract_snapshot(&page).await?;
411→
412→        debug!(
413→            session_id = sid,
414→            elements = snapshot.elements.len(),
415→            "extracted snapshot"
416→        );
417→
418→        Ok((
419→            sid.clone(),
420→            BrowserResponse::success(sid, 0, sandbox).with_snapshot(snapshot),
421→        ))
422→    }
423→
424→    /// Click an element by reference.
425→    async fn click(
426→        &self,
427→        session_id: Option<&str>,
428→        ref_: u32,
429→        sandbox: bool,
430→    ) -> Result<(String, BrowserResponse), Error> {
431→        let sid = require_session(session_id, "click")?;
432→
433→        let page = self.pool.get_page(&sid).await?;
434→
435→        // Scroll element into view first
436→        scroll_element_into_view(&page, ref_).await?;
437→
438→        // Small delay for scroll to complete
439→        tokio::time::sleep(Duration::from_millis(100)).await;
440→
441→        // Find element center
442→        let (x, y) = find_element_by_ref(&page, ref_).await?;
443→
444→        // Dispatch mouse events
445→        let press_cmd = DispatchMouseEventParams::builder()
446→            .r#type(DispatchMouseEventType::MousePressed)
447→            .x(x)
448→            .y(y)
449→            .button(MouseButton::Left)
450→            .click_count(1)
451→            .build()
452→            .map_err(|e| Error::Cdp(e.to_string()))?;
453→        page.execute(press_cmd)
454→            .await
455→            .map_err(|e| Error::Cdp(e.to_string()))?;
456→
457→        let release_cmd = DispatchMouseEventParams::builder()
458→            .r#type(DispatchMouseEventType::MouseReleased)
459→            .x(x)
460→            .y(y)
461→            .button(MouseButton::Left)
462→            .click_count(1)
463→            .build()
464→            .map_err(|e| Error::Cdp(e.to_string()))?;
465→        page.execute(release_cmd)
466→            .await
467→            .map_err(|e| Error::Cdp(e.to_string()))?;
468→
469→        debug!(
470→            session_id = sid,
471→            ref_ = ref_,
472→            x = x,
473→            y = y,
474→            "clicked element"
475→        );
476→
477→        Ok((sid.clone(), BrowserResponse::success(sid, 0, sandbox)))
478→    }
479→
480→    /// Type text into an element.
481→    async fn type_text(
482→        &self,
483→        session_id: Option<&str>,
484→        ref_: u32,
485→        text: &str,
486→        sandbox: bool,
487→    ) -> Result<(String, BrowserResponse), Error> {
488→        let sid = require_session(session_id, "type")?;
489→
490→        let page = self.pool.get_page(&sid).await?;
491→
492→        // Focus the element
493→        focus_element_by_ref(&page, ref_).await?;
494→
495→        // Type each character
496→        for c in text.chars() {
497→            let key_down = DispatchKeyEventParams::builder()
498→                .r#type(DispatchKeyEventType::KeyDown)
499→                .text(c.to_string())
500→                .build()
501→                .map_err(|e| Error::Cdp(e.to_string()))?;
502→            page.execute(key_down)
503→                .await
504→                .map_err(|e| Error::Cdp(e.to_string()))?;
505→
506→            let key_up = DispatchKeyEventParams::builder()
507→                .r#type(DispatchKeyEventType::KeyUp)
508→                .text(c.to_string())
509→                .build()
510→                .map_err(|e| Error::Cdp(e.to_string()))?;
511→            page.execute(key_up)
512→                .await
513→                .map_err(|e| Error::Cdp(e.to_string()))?;
514→        }
515→
516→        debug!(
517→            session_id = sid,
518→            ref_ = ref_,
519→            chars = text.len(),
520→            "typed text"
521→        );
522→
523→        Ok((sid.clone(), BrowserResponse::success(sid, 0, sandbox)))
524→    }
525→
526→    /// Scroll the page or an element.
527→    async fn scroll(
528→        &self,
529→        session_id: Option<&str>,
530→        ref_: Option<u32>,
531→        x: i32,
532→        y: i32,
533→        sandbox: bool,
534→    ) -> Result<(String, BrowserResponse), Error> {
535→        let sid = require_session(session_id, "scroll")?;
536→
537→        let page = self.pool.get_page(&sid).await?;
538→
539→        let js = if let Some(ref_) = ref_ {
540→            format!(
541→                r#"(() => {{
542→                    const el = document.querySelector(`[data-moltis-ref="{ref_}"]`);
543→                    if (el) el.scrollBy({x}, {y});
544→                    return !!el;
545→                }})()"#
546→            )
547→        } else {
548→            format!("window.scrollBy({x}, {y}); true")
549→        };
550→
551→        page.evaluate(js.as_str())
552→            .await
553→            .map_err(|e| Error::JsEvalFailed(e.to_string()))?;
554→
555→        debug!(session_id = sid, ref_ = ?ref_, x = x, y = y, "scrolled");
556→
557→        Ok((sid.clone(), BrowserResponse::success(sid, 0, sandbox)))
558→    }
559→
560→    /// Execute JavaScript in the page context.
561→    async fn evaluate(
562→        &self,
563→        session_id: Option<&str>,
564→        code: &str,
565→        sandbox: bool,
566→    ) -> Result<(String, BrowserResponse), Error> {
567→        let sid = require_session(session_id, "evaluate")?;
568→
569→        let page = self.pool.get_page(&sid).await?;
570→
571→        let result: serde_json::Value = page
572→            .evaluate(code)
573→            .await
574→            .map_err(|e| Error::JsEvalFailed(e.to_string()))?
575→            .into_value()
576→            .map_err(|e| Error::JsEvalFailed(format!("{e:?}")))?;
577→
578→        debug!(session_id = sid, "evaluated JavaScript");
579→
580→        Ok((
581→            sid.clone(),
582→            BrowserResponse::success(sid, 0, sandbox).with_result(result),
583→        ))
584→    }
585→
586→    /// Wait for an element to appear.
587→    async fn wait(
588→        &self,
589→        session_id: Option<&str>,
590→        selector: Option<String>,
591→        ref_: Option<u32>,
592→        timeout_ms: u64,
593→        sandbox: bool,
594→    ) -> Result<(String, BrowserResponse), Error> {
595→        let sid = require_session(session_id, "wait")?;
596→
597→        let page = self.pool.get_page(&sid).await?;
598→
599→        let check_js = if let Some(ref selector) = selector {
600→            format!(
601→                r#"document.querySelector({}) !== null"#,
602→                serde_json::to_string(selector).map_err(|e| Error::Cdp(e.to_string()))?
603→            )
604→        } else if let Some(ref_) = ref_ {
605→            format!(r#"document.querySelector('[data-moltis-ref="{ref_}"]') !== null"#)
606→        } else {
607→            return Err(Error::InvalidAction("wait requires selector or ref".into()));
608→        };
609→
610→        let deadline = Instant::now() + Duration::from_millis(timeout_ms);
611→        let interval = Duration::from_millis(100);
612→
613→        while Instant::now() < deadline {
614→            let found: bool = page
615→                .evaluate(check_js.as_str())
616→                .await
617→                .map_err(|e| Error::JsEvalFailed(e.to_string()))?
618→                .into_value()
619→                .unwrap_or(false);
620→
621→            if found {
622→                debug!(session_id = sid, "element found");
623→                return Ok((sid.clone(), BrowserResponse::success(sid, 0, sandbox)));
624→            }
625→
626→            tokio::time::sleep(interval).await;
627→        }
628→
629→        Err(Error::Timeout(format!(
630→            "element not found after {}ms",
631→            timeout_ms
632→        )))
633→    }
634→
635→    /// Get the current page URL.
