699→    ) -> Result<(String, BrowserResponse), Error> {
700→        let sid = require_session(session_id, "forward")?;
701→
702→        let page = self.pool.get_page(&sid).await?;
703→
704→        page.evaluate("history.forward()")
705→            .await
706→            .map_err(|e| Error::JsEvalFailed(e.to_string()))?;
707→
708→        // Wait for navigation
709→        let _ = page.wait_for_navigation().await;
710→
711→        let url = page.url().await.ok().flatten().unwrap_or_default();
