814→
815→/// Validate a URL before attempting navigation.
816→///
817→/// Checks for:
818→/// - Valid URL structure (can be parsed)
819→/// - Allowed schemes (http, https)
820→/// - Not obviously malformed (LLM garbage in path)
821→fn validate_url(url: &str) -> Result<(), Error> {
822→    // Check if URL is empty
823→    if url.is_empty() {
824→        return Err(Error::InvalidAction("URL cannot be empty".to_string()));
825→    }
826→
827→    // Parse the URL
828→    let parsed = url::Url::parse(url)
829→        .map_err(|e| Error::InvalidAction(format!("invalid URL '{}': {}", truncate_url(url), e)))?;
830→
831→    // Check scheme
832→    match parsed.scheme() {
833→        "http" | "https" => {},
834→        scheme => {
835→            return Err(Error::InvalidAction(format!(
836→                "unsupported URL scheme '{}', only http/https allowed",
837→                scheme
838→            )));
839→        },
840→    }
841→
842→    // Check for obviously malformed URLs (LLM garbage)
843→    // Check the original URL string (before normalization) to catch garbage
844→    let suspicious_patterns = [
845→        "}}}",           // JSON garbage
846→        "]}",            // JSON array closing
847→        "}<",            // Mixed JSON/XML
848→        "assistant to=", // LLM prompt leakage
849→        "functions.",    // LLM function call leakage (e.g., "functions.browser")
850→    ];
851→
852→    for pattern in suspicious_patterns {
853→        if url.contains(pattern) {
854→            warn!(
855→                url = %truncate_url(url),
856→                pattern = pattern,
857→                "rejecting URL with suspicious pattern (likely LLM garbage)"
858→            );
859→            return Err(Error::InvalidAction(format!(
860→                "URL contains invalid characters or LLM garbage: '{}'",
861→                truncate_url(url)
862→            )));
863→        }
864→    }
865→
866→    Ok(())
867→}
868→
869→/// Truncate a URL for error messages (to avoid huge garbage URLs in logs).
870→fn truncate_url(url: &str) -> String {
871→    if url.len() > 100 {
872→        format!("{}...", &url[..url.floor_char_boundary(100)])
873→    } else {
874→        url.to_string()
875→    }
876→}
