 30→/// Get current system memory usage as a percentage (0-100).
 31→fn get_memory_usage_percent() -> u8 {
 32→    let mut sys = System::new();
 33→    sys.refresh_memory();
 34→
 35→    let total = sys.total_memory();
 36→    if total == 0 {
 37→        return 0;
 38→    }
