 61→/// Build websocket connection candidates based on Browserless API version.
 62→///
 63→/// - v1 (default): connect only to the base URL.
 64→/// - v2: when URL path is root (`/`), also try `/chrome` and `/chromium`.
 65→fn websocket_connect_candidates(
 66→    base_ws_url: &str,
 67→    browserless_api_version: BrowserlessApiVersion,
 68→) -> Vec<String> {
 69→    let mut candidates = vec![base_ws_url.to_string()];
 70→    if browserless_api_version != BrowserlessApiVersion::V2 {
 71→        return candidates;
 72→    }
 73→
 74→    let Ok(parsed) = Url::parse(base_ws_url) else {
 75→        return candidates;
 76→    };
 77→    if parsed.path() != "/" {
 78→        return candidates;
 79→    }
 80→
 81→    for suffix in ["/chrome", "/chromium"] {
 82→        let mut with_suffix = parsed.clone();
 83→        with_suffix.set_path(suffix);
 84→        let candidate = with_suffix.to_string();
 85→        if !candidates.contains(&candidate) {
 86→            candidates.push(candidate);
 87→        }
 88→    }
 89→
 90→    candidates
 91→}
