 99→    /// prevents Chromium memory leaks from accumulating in long-lived instances.
100→    created_at: Instant,
101→    /// Whether this instance is running in sandbox mode.
102→    #[allow(dead_code)]
103→    sandboxed: bool,
104→    /// Container for sandboxed instances (None for host browser).
105→    #[allow(dead_code)]
106→    container: Option<BrowserContainer>,
107→}
108→
109→/// Pool of browser instances for reuse.
110→pub struct BrowserPool {
111→    config: BrowserConfig,
112→    instances: RwLock<HashMap<String, Arc<Mutex<BrowserInstance>>>>,
113→    #[cfg(feature = "metrics")]
114→    active_count: std::sync::atomic::AtomicUsize,
115→}
116→
117→impl BrowserPool {
118→    /// Create a new browser pool with the given configuration.
119→    pub fn new(config: BrowserConfig) -> Self {
120→        Self {
121→            config,
122→            instances: RwLock::new(HashMap::new()),
123→            #[cfg(feature = "metrics")]
124→            active_count: std::sync::atomic::AtomicUsize::new(0),
125→        }
126→    }
127→
128→    /// Get or create a browser instance for the given session ID.
129→    /// Returns the session ID for the browser instance.
130→    ///
131→    /// The `sandbox` parameter determines whether to run the browser in a
132→    /// Docker container (true) or on the host (false). This is set when
133→    /// creating a new session and cannot be changed for existing sessions.
134→    pub async fn get_or_create(
135→        &self,
136→        session_id: Option<&str>,
137→        sandbox: bool,
138→        browser: Option<BrowserPreference>,
139→    ) -> Result<String, Error> {
140→        // Treat empty string as None (generate new session ID)
141→        let session_id = session_id.filter(|s| !s.is_empty());
142→
143→        // Check if we have an existing instance
144→        if let Some(sid) = session_id {
145→            let instances = self.instances.read().await;
146→            if instances.contains_key(sid) {
147→                debug!(session_id = sid, "reusing existing browser instance");
148→                return Ok(sid.to_string());
149→            }
150→        }
151→
152→        // Check pool capacity using memory-based limits
153→        {
154→            // If max_instances is set (> 0), enforce it as a hard limit
155→            if self.config.max_instances > 0 {
156→                let instances = self.instances.read().await;
157→                if instances.len() >= self.config.max_instances {
158→                    drop(instances);
159→                    self.cleanup_idle().await;
160→
161→                    let instances = self.instances.read().await;
162→                    if instances.len() >= self.config.max_instances {
163→                        return Err(Error::PoolExhausted);
164→                    }
165→                }
166→            }
167→
168→            // Check memory usage - block new instances if above threshold
169→            let memory_percent = get_memory_usage_percent();
170→            if memory_percent >= self.config.memory_limit_percent {
171→                // Try to clean up idle instances first
172→                self.cleanup_idle().await;
173→
174→                // Re-check memory after cleanup
175→                let memory_after = get_memory_usage_percent();
176→                if memory_after >= self.config.memory_limit_percent {
177→                    warn!(
178→                        memory_usage = memory_after,
179→                        threshold = self.config.memory_limit_percent,
180→                        "blocking new browser instance due to high memory usage"
181→                    );
182→                    return Err(Error::PoolExhausted);
183→                }
184→            }
185→        }
186→
187→        // Create new instance
188→        let sid = session_id
189→            .map(String::from)
190→            .unwrap_or_else(generate_session_id);
191→
192→        let instance = self.launch_browser(&sid, sandbox, browser).await?;
193→        let instance = Arc::new(Mutex::new(instance));
194→
195→        {
196→            let mut instances = self.instances.write().await;
197→            instances.insert(sid.clone(), instance);
198→        }
199→
200→        #[cfg(feature = "metrics")]
201→        {
202→            self.active_count
203→                .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
204→            moltis_metrics::gauge!(moltis_metrics::browser::INSTANCES_ACTIVE)
205→                .set(self.active_count.load(std::sync::atomic::Ordering::Relaxed) as f64);
206→            moltis_metrics::counter!(moltis_metrics::browser::INSTANCES_CREATED_TOTAL).increment(1);
207→        }
208→
209→        let mode = if sandbox {
210→            "sandboxed"
211→        } else {
212→            "host"
213→        };
214→        info!(session_id = sid, mode, "launched new browser instance");
215→        Ok(sid)
216→    }
217→
218→    /// Get the page for a session, creating one if needed.
219→    pub async fn get_page(&self, session_id: &str) -> Result<Page, Error> {
220→        let instances = self.instances.read().await;
221→        let instance = instances.get(session_id).ok_or(Error::ElementNotFound(0))?;
222→
223→        let mut inst = instance.lock().await;
224→        inst.last_used = Instant::now();
225→
226→        // Get or create the main page
227→        if let Some(page) = inst.pages.get("main") {
228→            debug!(session_id, "reusing existing page");
229→            return Ok(page.clone());
230→        }
231→
232→        // Create a new page
233→        let page = inst
234→            .browser
235→            .new_page("about:blank")
236→            .await
237→            .map_err(|e| Error::LaunchFailed(e.to_string()))?;
238→
239→        // Explicitly set viewport on page to ensure it matches config
240→        // (browser-level viewport may not always be applied to new pages)
241→        let viewport_cmd = SetDeviceMetricsOverrideParams::builder()
242→            .width(self.config.viewport_width)
243→            .height(self.config.viewport_height)
244→            .device_scale_factor(self.config.device_scale_factor)
245→            .mobile(false)
246→            .build()
247→            .map_err(|e| Error::Cdp(format!("invalid viewport params: {e}")))?;
248→
249→        if let Err(e) = page.execute(viewport_cmd).await {
250→            warn!(session_id, error = %e, "failed to set page viewport");
251→        }
252→
253→        info!(
254→            session_id,
255→            viewport_width = self.config.viewport_width,
256→            viewport_height = self.config.viewport_height,
257→            device_scale_factor = self.config.device_scale_factor,
258→            "created new page with viewport"
259→        );
260→
261→        inst.pages.insert("main".to_string(), page.clone());
262→        Ok(page)
263→    }
264→
265→    /// Close a specific browser session.
266→    pub async fn close_session(&self, session_id: &str) -> Result<(), Error> {
267→        let instance = {
268→            let mut instances = self.instances.write().await;
269→            instances.remove(session_id)
270→        };
271→
272→        if let Some(instance) = instance {
273→            let inst = instance.lock().await;
274→            // Pages are closed when browser is dropped
275→            drop(inst);
276→
277→            #[cfg(feature = "metrics")]
278→            {
279→                self.active_count
280→                    .fetch_sub(1, std::sync::atomic::Ordering::Relaxed);
281→                moltis_metrics::gauge!(moltis_metrics::browser::INSTANCES_ACTIVE)
282→                    .set(self.active_count.load(std::sync::atomic::Ordering::Relaxed) as f64);
283→                moltis_metrics::counter!(moltis_metrics::browser::INSTANCES_DESTROYED_TOTAL)
284→                    .increment(1);
285→            }
286→
287→            info!(session_id, "closed browser session");
288→        }
289→
290→        Ok(())
291→    }
292→
293→    /// Clean up idle browser instances and instances that have exceeded the
294→    /// hard TTL ([`MAX_BROWSER_INSTANCE_LIFETIME`]). The TTL prevents Chromium
295→    /// memory leaks from accumulating in long-lived browser instances.
296→    pub async fn cleanup_idle(&self) {
297→        let idle_timeout = Duration::from_secs(self.config.idle_timeout_secs);
298→        let now = Instant::now();
299→
300→        let mut to_remove = Vec::new();
301→
302→        {
303→            let instances = self.instances.read().await;
304→            for (sid, instance) in instances.iter() {
305→                if let Ok(inst) = instance.try_lock() {
306→                    let idle = now.duration_since(inst.last_used) > idle_timeout;
307→                    let expired =
308→                        now.duration_since(inst.created_at) > MAX_BROWSER_INSTANCE_LIFETIME;
309→                    if idle || expired {
310→                        if expired {
311→                            info!(
312→                                session_id = sid,
313→                                age_secs = inst.created_at.elapsed().as_secs(),
314→                                "browser instance exceeded max lifetime"
315→                            );
316→                        }
317→                        to_remove.push(sid.clone());
318→                    }
319→                }
320→            }
321→        }
322→
323→        if to_remove.is_empty() {
324→            return;
325→        }
326→
327→        info!(
328→            count = to_remove.len(),
329→            sessions = ?to_remove,
330→            "cleaning up browser sessions"
331→        );
332→
333→        for sid in to_remove {
334→            if let Err(e) = self.close_session(&sid).await {
335→                warn!(session_id = sid, error = %e, "failed to close session");
336→            }
337→        }
338→    }
339→
340→    /// Shut down all browser instances.
341→    pub async fn shutdown(&self) {
342→        let sessions: Vec<String> = {
343→            let instances = self.instances.read().await;
344→            instances.keys().cloned().collect()
345→        };
346→
347→        for sid in sessions {
348→            let _ = self.close_session(&sid).await;
349→        }
350→
351→        info!("browser pool shut down");
352→    }
353→
354→    /// Get the number of active instances.
355→    pub async fn active_count(&self) -> usize {
356→        self.instances.read().await.len()
357→    }
358→
359→    /// Launch a new browser instance.
360→    async fn launch_browser(
361→        &self,
362→        session_id: &str,
363→        sandbox: bool,
364→        browser: Option<BrowserPreference>,
365→    ) -> Result<BrowserInstance, Error> {
366→        if sandbox {
367→            self.launch_sandboxed_browser(session_id).await
368→        } else {
369→            self.launch_host_browser(session_id, browser).await
370→        }
371→    }
372→
373→    /// Launch a browser inside a container (sandboxed mode).
374→    async fn launch_sandboxed_browser(&self, session_id: &str) -> Result<BrowserInstance, Error> {
375→        use crate::container;
376→
377→        // All container operations (CLI checks, image pulls, container start +
378→        // readiness polling) use synchronous `std::process::Command` and
379→        // `std::thread::sleep`.  Run them on the blocking thread-pool so they
380→        // don't stall the tokio event loop.
381→        let image = self.config.sandbox_image.clone();
382→        let prefix = self.config.container_prefix.clone();
383→        let vw = self.config.viewport_width;
384→        let vh = self.config.viewport_height;
385→        let low_mem = self.config.low_memory_threshold_mb;
386→        let session_timeout_ms = browserless_session_timeout_ms(
387→            self.config.idle_timeout_secs,
388→            self.config.navigation_timeout_ms,
389→            MAX_BROWSER_INSTANCE_LIFETIME.as_secs(),
390→        );
391→        let profile_dir = sandbox_profile_dir(self.config.resolved_profile_dir(), session_id);
392→        let container_host = self.config.container_host.clone();
393→
394→        let container = tokio::task::spawn_blocking(move || {
395→            // Check container runtime availability (Docker, Podman, or Apple Container)
396→            if !container::is_container_available() {
397→                return Err(Error::LaunchFailed(
398→                    "No container runtime available for sandboxed browser. \
399→                     Please install Docker, Podman, or Apple Container."
400→                        .to_string(),
401→                ));
402→            }
403→
404→            // Ensure the container image is available
405→            let t_image = Instant::now();
406→            container::ensure_image(&image)
407→                .map_err(|e| Error::LaunchFailed(format!("failed to ensure browser image: {e}")))?;
408→            info!(
409→                elapsed_ms = t_image.elapsed().as_millis() as u64,
410→                "browser container image ready"
411→            );
412→
413→            // Create profile directory on host if needed.
414→            // The directory must be world-writable (0o777) because the browserless/chrome
415→            // container runs Chrome as uid 999 (`chrome` user), which differs from the
416→            // host uid that owns this directory. Without open permissions the bind-mounted
417→            // volume is not writable and Chrome crashes on startup.
418→            // This is safe: the directory is Moltis-managed (~/.moltis/browser/profile/)
419→            // and contains only ephemeral Chrome profile data (cache, cookies, local
420→            // storage). It is not a system directory and has no security-sensitive content.
421→            if let Some(ref dir) = profile_dir {
422→                match std::fs::create_dir_all(dir) {
423→                    Err(e) => warn!(
424→                        path = %dir.display(),
425→                        error = %e,
426→                        "failed to create browser profile directory for container"
427→                    ),
428→                    Ok(()) => set_container_dir_permissions(dir),
429→                }
430→            }
431→
432→            // Start the container (includes readiness polling)
433→            BrowserContainer::start(
434→                &image,
435→                &prefix,
436→                vw,
437→                vh,
438→                low_mem,
439→                session_timeout_ms,
440→                profile_dir.as_deref(),
441→                &container_host,
442→            )
443→            .map_err(|e| Error::LaunchFailed(format!("failed to start browser container: {e}")))
444→        })
445→        .await
446→        .map_err(|e| Error::LaunchFailed(format!("container launch task panicked: {e}")))??;
447→
448→        let ws_url = container.websocket_url();
449→        info!(
450→            session_id,
451→            container_id = container.id(),
452→            ws_url,
453→            "connecting to sandboxed browser"
454→        );
455→
456→        let ws_candidates =
457→            websocket_connect_candidates(&ws_url, self.config.browserless_api_version);
458→        let mut last_error = String::new();
459→        let mut connected = None;
460→        for candidate in &ws_candidates {
461→            let attempt_config = HandlerConfig {
462→                request_timeout: Duration::from_millis(self.config.navigation_timeout_ms),
463→                viewport: Some(chromiumoxide::handler::viewport::Viewport {
464→                    width: self.config.viewport_width,
465→                    height: self.config.viewport_height,
466→                    device_scale_factor: Some(self.config.device_scale_factor),
467→                    emulating_mobile: false,
468→                    is_landscape: true,
469→                    has_touch: false,
470→                }),
471→                ..Default::default()
472→            };
473→
474→            match Browser::connect_with_config(candidate, attempt_config).await {
475→                Ok(pair) => {
476→                    if candidate != &ws_url {
477→                        info!(
478→                            session_id,
479→                            original_ws_url = ws_url,
480→                            ws_url = candidate,
481→                            browserless_api_version = %self.config.browserless_api_version,
482→                            "sandboxed browser connected using fallback websocket path"
483→                        );
484→                    }
485→                    connected = Some(pair);
486→                    break;
487→                },
488→                Err(e) => {
489→                    last_error = e.to_string();
490→                    debug!(
491→                        session_id,
492→                        ws_url = candidate,
493→                        browserless_api_version = %self.config.browserless_api_version,
494→                        error = %last_error,
495→                        "sandboxed browser websocket candidate failed, trying next"
496→                    );
497→                },
498→            }
499→        }
500→
501→        let (browser, mut handler) = connected.ok_or_else(|| {
502→            Error::LaunchFailed(format!(
503→                "failed to connect to containerized browser at {} (candidates: {}): {}",
504→                ws_url,
505→                ws_candidates.join(", "),
506→                last_error
507→            ))
508→        })?;
509→
510→        // Spawn handler to process browser events
511→        let session_id_clone = session_id.to_string();
512→        tokio::spawn(async move {
513→            while let Some(event) = handler.next().await {
514→                debug!(session_id = session_id_clone, ?event, "browser event");
515→            }
516→            // Handler exits when connection closes - this is normal for idle sessions
517→            debug!(
518→                session_id = session_id_clone,
519→                "sandboxed browser event handler exited (connection closed)"
520→            );
521→        });
522→
523→        info!(session_id, "sandboxed browser connected successfully");
524→
525→        Ok(BrowserInstance {
526→            browser,
527→            pages: HashMap::new(),
528→            last_used: Instant::now(),
529→            created_at: Instant::now(),
530→            sandboxed: true,
531→            container: Some(container),
532→        })
533→    }
534→
535→    /// Launch a browser on the host (non-sandboxed mode).
536→    async fn launch_host_browser(
537→        &self,
538→        session_id: &str,
539→        browser: Option<BrowserPreference>,
540→    ) -> Result<BrowserInstance, Error> {
541→        let requested_browser = browser.unwrap_or_default();
542→
543→        // Detect all installed browser candidates.
544→        let mut detection = crate::detect::detect_browser(self.config.chrome_path.as_deref());
545→        let mut install_attempt: Option<crate::detect::AutoInstallResult> = None;
546→
547→        // Auto-install is always on: if none are installed, try to install one.
548→        if detection.browsers.is_empty() {
549→            let result = crate::detect::auto_install_browser(requested_browser).await;
550→            if result.attempted && result.installed {
551→                info!(details = %result.details, "auto-installed browser on host");
552→            } else if result.attempted {
553→                warn!(details = %result.details, "browser auto-install failed");
554→            } else {
555→                warn!(
556→                    details = %result.details,
557→                    "browser auto-install skipped (installer unavailable)"
558→                );
559→            }
560→            install_attempt = Some(result);
561→            detection = crate::detect::detect_browser(self.config.chrome_path.as_deref());
562→        }
563→
564→        if detection.browsers.is_empty() {
565→            let mut message = format!("No compatible browser found. {}", detection.install_hint);
566→            if let Some(attempt) = install_attempt
567→                && attempt.attempted
568→            {
569→                message.push_str("\n\nAuto-install attempt:\n");
570→                message.push_str(&attempt.details);
571→            }
572→            return Err(Error::LaunchFailed(message));
573→        }
574→
575→        let selected =
576→            match crate::detect::pick_browser(&detection.browsers, Some(requested_browser)) {
577→                Some(browser) => browser,
578→                None => {
579→                    let installed = crate::detect::installed_browser_labels(&detection.browsers);
580→                    let installed_list = if installed.is_empty() {
581→                        "none".to_string()
582→                    } else {
583→                        installed.join(", ")
584→                    };
585→                    return Err(Error::LaunchFailed(format!(
586→                        "requested browser '{}' is not installed. Installed browsers: {}",
587→                        requested_browser, installed_list
588→                    )));
589→                },
590→            };
591→
592→        let mut builder = CdpBrowserConfig::builder();
593→
594→        // with_head() shows the browser window (non-headless mode)
595→        // By default chromiumoxide runs headless, so we only call with_head() when NOT headless
596→        if !self.config.headless {
597→            builder = builder.with_head();
598→        }
599→
600→        info!(
601→            session_id,
602→            viewport_width = self.config.viewport_width,
603→            viewport_height = self.config.viewport_height,
604→            device_scale_factor = self.config.device_scale_factor,
605→            headless = self.config.headless,
606→            "configuring browser viewport"
607→        );
608→
609→        builder = builder
610→            .viewport(chromiumoxide::handler::viewport::Viewport {
611→                width: self.config.viewport_width,
612→                height: self.config.viewport_height,
613→                device_scale_factor: Some(self.config.device_scale_factor),
614→                emulating_mobile: false,
615→                is_landscape: true,
616→                has_touch: false,
617→            })
618→            .request_timeout(Duration::from_millis(self.config.navigation_timeout_ms));
619→
620→        // User agent can be set via Chrome arg instead of builder method
621→        if let Some(ref ua) = self.config.user_agent {
622→            builder = builder.arg(format!("--user-agent={ua}"));
623→        }
624→        builder = builder.chrome_executable(selected.path.clone());
625→
626→        for arg in &self.config.chrome_args {
627→            builder = builder.arg(arg);
628→        }
629→
630→        // Set persistent profile directory if configured
631→        if let Some(ref profile_path) = self.config.resolved_profile_dir() {
632→            if let Err(e) = std::fs::create_dir_all(profile_path) {
633→                warn!(
634→                    path = %profile_path.display(),
635→                    error = %e,
636→                    "failed to create browser profile directory, falling back to ephemeral"
637→                );
638→            } else {
639→                info!(
640→                    path = %profile_path.display(),
641→                    "using persistent browser profile"
642→                );
643→                builder = builder.user_data_dir(profile_path);
644→            }
645→        }
646→
647→        // Additional security/sandbox args for headless
648→        builder = builder
649→            .arg("--disable-gpu")
650→            .arg("--disable-dev-shm-usage")
651→            .arg("--disable-software-rasterizer")
652→            .arg("--no-sandbox")
653→            .arg("--disable-setuid-sandbox");
654→
655→        // Auto-inject low-memory flags on constrained systems
656→        if self.config.low_memory_threshold_mb > 0 {
657→            let mut sys = System::new();
658→            sys.refresh_memory();
659→            let total_mb = sys.total_memory() / (1024 * 1024);
660→            let extra = low_memory_chrome_args(total_mb, self.config.low_memory_threshold_mb);
661→            if !extra.is_empty() {
662→                info!(
663→                    total_mb,
664→                    threshold = self.config.low_memory_threshold_mb,
665→                    "low memory detected, adding constrained Chrome flags"
666→                );
667→                for arg in extra {
668→                    builder = builder.arg(*arg);
669→                }
670→            }
671→        }
672→
673→        let config = builder
674→            .build()
675→            .map_err(|e| Error::LaunchFailed(format!("failed to build browser config: {e}")))?;
676→
677→        let (browser, mut handler) = Browser::launch(config).await.map_err(|e| {
678→            // Include install instructions in launch failure messages
679→            let install_hint = crate::detect::install_instructions();
680→            Error::LaunchFailed(format!("browser launch failed: {e}\n\n{install_hint}"))
681→        })?;
682→
683→        info!(
684→            session_id,
685→            browser = %selected.kind,
686→            path = %selected.path.display(),
687→            "launched host browser executable"
688→        );
689→
690→        // Spawn handler to process browser events
691→        let session_id_clone = session_id.to_string();
692→        tokio::spawn(async move {
693→            while let Some(event) = handler.next().await {
694→                debug!(session_id = session_id_clone, ?event, "browser event");
695→            }
696→        });
697→
698→        Ok(BrowserInstance {
699→            browser,
700→            pages: HashMap::new(),
701→            last_used: Instant::now(),
702→            created_at: Instant::now(),
703→            sandboxed: false,
704→            container: None,
705→        })
706→    }
707→}
