709→impl Drop for BrowserPool {
710→    fn drop(&mut self) {
711→        let instances = self.instances.get_mut();
712→        let count = instances.len();
713→        if count > 0 {
714→            info!(
715→                count,
716→                "browser pool dropping, stopping remaining containers"
717→            );
718→        }
719→    }
720→}
