722→/// Generate a random session ID.
723→fn generate_session_id() -> String {
724→    use rand::RngExt;
725→    let mut rng = rand::rng();
726→    let id: u64 = rng.random();
727→    format!("browser-{:016x}", id)
728→}
729→
730→/// Sanitize a session identifier to a filesystem-safe single path segment.
731→fn sanitize_session_component(session_id: &str) -> String {
732→    let sanitized: String = session_id
733→        .chars()
734→        .map(|ch| match ch {
735→            'a'..='z' | 'A'..='Z' | '0'..='9' | '-' | '_' => ch,
736→            _ => '_',
737→        })
738→        .collect();
739→
740→    if sanitized.is_empty() {
741→        return "session".to_string();
742→    }
743→
744→    sanitized
745→}
